import React, { useState } from 'react';
import { Button, dispatchAppToast } from '@linm-soft/common-components';
import { AnalyticsReportShell } from '../../../components/report';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import type {
  MasterDataImportRunDetail,
  MasterDataImportRunListItem,
} from '../../../services/analytics/importTrackingModels';
import { formatNumber } from '../../../utils/formatters';
import styles from '../../../styles/erpReportPage.module.css';
import local from './TongHopImportDuLieuPage.module.css';

const statusClass = (s: string) => {
  if (s === 'Success') return local.statusSuccess;
  if (s === 'Partial') return local.statusPartial;
  if (s === 'Failed') return local.statusFailed;
  return local.statusSkipped;
};

const fmtDt = (iso?: string | null) => {
  if (!iso) return '—';
  try {
    return new Date(iso).toLocaleString('vi-VN');
  } catch {
    return iso;
  }
};

const ProgressBar: React.FC<{ percent: number; done?: number; total?: number }> = ({ percent, done, total }) => (
  <div>
    <div className={local.progressBar} aria-hidden>
      <div className={local.progressFill} style={{ width: `${Math.min(100, Math.max(0, percent))}%` }} />
    </div>
    {(done != null && total != null && total > 0) && (
      <div className={local.progressLabel}>
        {formatNumber(done)}/{formatNumber(total)} ({percent}%)
      </div>
    )}
  </div>
);

const TongHopImportDuLieuPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [reimporting, setReimporting] = useState(false);

  const openAction = (err: {
    deepLinkPath?: string | null;
    code?: string | null;
    suggestedAction: string;
  }) => {
    if (err.suggestedAction === 'REGENERATE_AND_REIMPORT') {
      dispatchAppToast(dispatch, { message: 'Chạy /reva-master-data-reimport sau khi sửa nguồn CSV', type: 'info' });
      return;
    }
    if (err.deepLinkPath) {
      const q = err.code ? `?legacyId=${encodeURIComponent(err.code)}` : '';
      window.location.href = `${err.deepLinkPath}${q}`;
      return;
    }
    dispatchAppToast(dispatch, { message: 'Xem docs/master-data-import-tracking.md', type: 'info' });
  };
  const [runs, setRuns] = useState<MasterDataImportRunListItem[]>([]);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(1);
  const [loading, setLoading] = useState(false);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [detail, setDetail] = useState<MasterDataImportRunDetail | null>(null);

  const loadRuns = React.useCallback(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      analyticsService
        .getMasterDataImportRuns({ page, pageSize: 15 })
        .then((r) => {
          if (!cancelled) {
            setRuns(r.items);
            setTotal(r.total);
          }
        })
        .catch((e: Error) => {
          if (!cancelled) dispatchAppToast(dispatch, { message: e?.message ?? 'Lỗi tải danh sách import', type: 'error' });
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [page, dispatch]);

  React.useEffect(() => loadRuns(), [loadRuns]);

  React.useEffect(() => {
    if (!selectedId || detail?.status !== 'Running') return undefined;
    const t = setInterval(() => {
      analyticsService.getMasterDataImportRun(selectedId).then(setDetail).catch(() => undefined);
      loadRuns();
    }, 4000);
    return () => clearInterval(t);
  }, [selectedId, detail?.status, loadRuns]);

  const triggerReimport = (sets?: string[]) => {
    setReimporting(true);
    analyticsService
      .triggerDataSyncSeed({ sets, forceReImport: true, trigger: 'UiReimport' })
      .then((res) => {
        dispatchAppToast(dispatch, { message: `Đã enqueue import — run ${res.runId.slice(0, 8)}…`, type: 'success' });
        loadRuns();
        if (res.runId) loadDetail(res.runId);
      })
      .catch((e: Error) =>
        dispatchAppToast(dispatch, { message: e?.message ?? 'Lỗi enqueue import', type: 'error' }),
      )
      .finally(() => setReimporting(false));
  };

  const loadDetail = (id: string) => {
    setSelectedId(id);
    setDetail(null);
    const t = setTimeout(() => {
      analyticsService
        .getMasterDataImportRun(id)
        .then(setDetail)
        .catch((e: Error) =>
          dispatchAppToast(dispatch, { message: e?.message ?? 'Lỗi tải chi tiết', type: 'error' }),
        );
    }, 0);
    return () => clearTimeout(t);
  };

  const s = detail?.summary;

  const handleRefresh = () => {
    loadRuns();
  };

  return (
    <AnalyticsReportShell
      testId="erp-tong-hop-import"
      pageId="baocao-tong-hop-import"
      title="Tổng hợp import dữ liệu"
      titleIconClass="fas fa-database"
      loading={loading}
      hasData={runs.length > 0 || !!detail}
      suppressEmptyGate
      filterItems={[
        {
          testId: 'erp-tong-hop-import-reimport',
          content: (
            <Button
              variant="primary"
              size="sm"
              disabled={reimporting}
              onClick={() => triggerReimport()}
              data-testid="bc-import-reimport-all"
            >
              {reimporting ? 'Đang enqueue…' : 'Import lại REVA_*'}
            </Button>
          ),
        },
      ]}
      onLoad={handleRefresh}
      emptyMessage=""
    >
      {loading ? (
        <div className={styles.loading}>
          <i className="fas fa-spinner fa-spin" />
        </div>
      ) : (
        <>
          <div className={styles.tableCard}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Thời gian</th>
                  <th>Trạng thái</th>
                  <th>Nguồn</th>
                  <th>Tiến độ CT</th>
                  <th>Set OK</th>
                  <th>TK upsert</th>
                  <th>PNK (CSV)</th>
                  <th>Posted</th>
                  <th>Draft</th>
                  <th>Lỗi mẫu</th>
                </tr>
              </thead>
              <tbody>
                {runs.map((r) => (
                  <tr
                    key={r.id}
                    className={`${local.runRow} ${selectedId === r.id ? local.runRowActive : ''}`}
                    onClick={() => loadDetail(r.id)}
                    data-testid={`bc-import-run-${r.id}`}
                  >
                    <td>{fmtDt(r.startedAtUtc)}</td>
                    <td className={statusClass(r.status)}>{r.status}</td>
                    <td>{r.sourceKind ?? r.trigger}</td>
                    <td>
                      {r.status === 'Running' && r.progressPercent != null ? (
                        <ProgressBar
                          percent={r.progressPercent}
                          done={r.documentsDone ?? undefined}
                          total={r.documentsTotal ?? undefined}
                        />
                      ) : r.documentsTotal ? (
                        <span>{formatNumber(r.documentsDone ?? 0)}/{formatNumber(r.documentsTotal)}</span>
                      ) : (
                        '—'
                      )}
                    </td>
                    <td>
                      {r.summary.setsSuccess}/{r.summary.setsTotal}
                    </td>
                    <td>{formatNumber(r.summary.catalogRowsUpserted)}</td>
                    <td>{formatNumber(r.summary.voucherHeadersTotal)}</td>
                    <td>{formatNumber(r.summary.voucherHeadersPosted)}</td>
                    <td>{formatNumber(r.summary.voucherHeadersDraft)}</td>
                    <td>{formatNumber(r.summary.errorSampleCount)}</td>
                  </tr>
                ))}
                {runs.length === 0 && (
                  <tr>
                    <td colSpan={10} style={{ textAlign: 'center', padding: 24 }}>
                      Chưa có lần import — chạy Docker/CLI với ReImportSeed=true
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>

          <div style={{ marginTop: 8, display: 'flex', gap: 8 }}>
            <Button
              variant="secondary"
              size="sm"
              disabled={page <= 1}
              onClick={() => setPage((p) => Math.max(1, p - 1))}
            >
              Trước
            </Button>
            <span>
              Trang {page} / {Math.max(1, Math.ceil(total / 15))}
            </span>
            <Button
              variant="secondary"
              size="sm"
              disabled={page * 15 >= total}
              onClick={() => setPage((p) => p + 1)}
            >
              Sau
            </Button>
          </div>

          {detail && s && (
            <div className={local.detailPanel} data-testid="bc-import-detail">
              <h2 className={local.subTitle}>
                Chi tiết — {fmtDt(detail.startedAtUtc)} · <span className={statusClass(detail.status)}>{detail.status}</span>
                {detail.sourceKind ? ` · ${detail.sourceKind}` : ''}
              </h2>
              {detail.status === 'Running' && detail.progress && (
                <ProgressBar
                  percent={detail.progress.progressPercent}
                  done={detail.progress.documentsDone}
                  total={detail.progress.documentsTotal}
                />
              )}
              <div className={local.reimportRow}>
                <Button
                  variant="secondary"
                  size="sm"
                  disabled={reimporting}
                  onClick={() => triggerReimport(detail.setsRequested)}
                  data-testid="bc-import-reimport-run-sets"
                >
                  Import lại các set của run này
                </Button>
                {detail.setResults
                  .filter((set) => !set.skipped && (set.status === 'Partial' || set.status === 'Failed'))
                  .map((set) => (
                    <Button
                      key={set.setName}
                      variant="secondary"
                      size="sm"
                      disabled={reimporting}
                      onClick={() => triggerReimport([set.setName])}
                      data-testid={`bc-import-reimport-${set.setName}`}
                    >
                      Import lại {set.setName}
                    </Button>
                  ))}
              </div>
              <div className={local.kpiGrid4}>
                <div className={styles.kpiCard}>
                  <div className={styles.kpiLabel}>Danh mục (dòng CSV)</div>
                  <div className={styles.kpiValue}>{formatNumber(s.catalogRowsTotal)}</div>
                </div>
                <div className={styles.kpiCard}>
                  <div className={styles.kpiLabel}>Đã upsert TK</div>
                  <div className={styles.kpiValue}>{formatNumber(s.catalogRowsUpserted)}</div>
                </div>
                <div className={styles.kpiCard}>
                  <div className={styles.kpiLabel}>Phiếu nhập Posted</div>
                  <div className={styles.kpiValue}>{formatNumber(s.voucherHeadersPosted)}</div>
                </div>
                <div className={styles.kpiCard}>
                  <div className={styles.kpiLabel}>Phiếu nhập Draft</div>
                  <div className={styles.kpiValue}>{formatNumber(s.voucherHeadersDraft)}</div>
                </div>
              </div>
              {(s.voucherCodesAssigned ?? 0) > 0 && (
                <p className={local.subTitle}>
                  Mã chứng từ IdCode: {formatNumber(s.voucherCodesNewInsert ?? 0)} phiếu mới ·{' '}
                  {formatNumber(s.voucherCodesAssigned ?? 0)} bản ghi map (mẫu)
                </p>
              )}

              <h3 className={local.subTitle}>Theo import set</h3>
              <div className={styles.tableCard}>
                <table className={styles.table}>
                  <thead>
                    <tr>
                      <th>Set</th>
                      <th>Tiến độ</th>
                      <th>Skipped</th>
                      <th>Catalog / file</th>
                      <th>Tổng dòng</th>
                      <th>Upsert</th>
                      <th>Posted</th>
                      <th>Draft</th>
                      <th>Lỗi</th>
                    </tr>
                  </thead>
                  <tbody>
                    {detail.setResults.flatMap((set) =>
                      (set.catalogs.length > 0 ? set.catalogs : [{ catalog: '—', fileName: '', rowsTotal: 0, rowsUpserted: 0, rowsFailed: 0, rowsSkipped: 0, rowsPosted: 0, rowsDraft: 0, outcome: '' }]).map((c) => (
                        <tr key={`${set.setName}-${c.fileName || 'empty'}`}>
                          <td>
                            {set.setName}
                            <br />
                            <span className={statusClass(set.status)}>{set.status}</span>
                          </td>
                          <td>
                            {set.progress && set.progress.documentsTotal > 0 ? (
                              <ProgressBar
                                percent={set.progress.progressPercent}
                                done={set.progress.documentsDone}
                                total={set.progress.documentsTotal}
                              />
                            ) : (
                              '—'
                            )}
                          </td>
                          <td>{set.skipped ? set.skipReason ?? 'Skipped' : '—'}</td>
                          <td>
                            {c.catalog}
                            {c.fileName ? (
                              <>
                                <br />
                                <small>{c.fileName}</small>
                              </>
                            ) : null}
                          </td>
                          <td>{formatNumber(c.rowsTotal)}</td>
                          <td>{formatNumber(c.rowsUpserted)}</td>
                          <td>{formatNumber(c.rowsPosted)}</td>
                          <td>{formatNumber(c.rowsDraft)}</td>
                          <td>{formatNumber(c.rowsFailed)}</td>
                        </tr>
                      )),
                    )}
                  </tbody>
                </table>
              </div>

              {detail.voucherCodeSamples?.length > 0 && (
                <>
                  <h3 className={local.subTitle}>
                    Map mã chứng từ (legacy → IdCode) — {detail.voucherCodeSamples.length} mẫu
                  </h3>
                  <div className={styles.tableCard}>
                    <table className={styles.table}>
                      <thead>
                        <tr>
                          <th>Số CT cũ (legacyId)</th>
                          <th>Mã cũ</th>
                          <th>Số chứng từ (voucherCode)</th>
                          <th>Ngày CT</th>
                          <th>Mới</th>
                        </tr>
                      </thead>
                      <tbody>
                        {detail.voucherCodeSamples.slice(0, 50).map((v, idx) => (
                          <tr key={`${v.legacyId}-${idx}`} data-testid={`bc-import-voucher-code-${idx}`}>
                            <td>{v.legacyId}</td>
                            <td>{v.legacyCode ?? '—'}</td>
                            <td>{v.voucherCode}</td>
                            <td>{v.voucherDate}</td>
                            <td>{v.isNewInsert ? 'Có' : '—'}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </>
              )}

              <h3 className={local.subTitle}>Lỗi mẫu &amp; hành động ({detail.errorSamples.length})</h3>
              <div className={styles.tableCard}>
                <table className={styles.table}>
                  <thead>
                    <tr>
                      <th>Set</th>
                      <th>Mã</th>
                      <th>Mã lỗi</th>
                      <th>Thông báo</th>
                      <th>Hành động</th>
                    </tr>
                  </thead>
                  <tbody>
                    {detail.errorSamples.slice(0, 100).map((e, idx) => (
                      <tr key={`${e.rowKey}-${idx}`} data-testid={`bc-import-error-${idx}`}>
                        <td>{e.setName}</td>
                        <td>{e.code ?? e.rowKey}</td>
                        <td>{e.errorCode}</td>
                        <td title={e.message}>{e.message.length > 80 ? `${e.message.slice(0, 80)}…` : e.message}</td>
                        <td>
                          <Button
                            variant="secondary"
                            size="sm"
                            className={local.actionBtn}
                            onClick={() => openAction(e)}
                          >
                            {e.actionLabelVi ?? e.suggestedAction}
                          </Button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </>
      )}
    </AnalyticsReportShell>
  );
};

export default TongHopImportDuLieuPage;
